## 팔로우 목록 조회 쿼리 최적화 가이드

### 1. 권장 Entity 구조

```kotlin
// Follow Entity (팔로우 관계)
@Entity
@Table(catalog = "maum", name = "follow", indexes = [
    Index(name = "idx_follower_id", columnList = "follower_id"),
    Index(name = "idx_following_id", columnList = "following_id"),
    Index(name = "idx_follower_following", columnList = "follower_id,following_id", unique = true)
])
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(name = "follower_id", nullable = false)
    val followerId: String,

    @Column(name = "following_id", nullable = false)
    val followingId: String,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "follower_id", insertable = false, updatable = false)
    val followerUser: UserEntity? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "following_id", insertable = false, updatable = false)
    val followingUser: UserEntity? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

### 2. 최적화된 Repository 구현

```kotlin
@Repository
interface FollowRepository : JpaRepository<FollowEntity, String>, FollowRepositoryCustom {
    // 단순 JPA 메서드 (인덱스 활용)
    fun findByFollowerId(followerId: String): List<FollowEntity>

    fun findByFollowingId(followingId: String): List<FollowEntity>

    fun findByFollowerIdAndFollowingId(followerId: String, followingId: String): FollowEntity?

    fun deleteByFollowerIdAndFollowingId(followerId: String, followingId: String)
}

interface FollowRepositoryCustom {
    fun findFollowingListWithUser(followerId: String, pageable: Pageable): Page<FollowEntity>

    fun findFollowerListWithUser(followingId: String, pageable: Pageable): Page<FollowEntity>

    fun findFollowingUserIds(followerId: String): List<String>

    fun findFollowerUserIds(followingId: String): List<String>
}

@Repository
class FollowRepositoryCustomImpl(
    private val queryFactory: JPAQueryFactory
) : FollowRepositoryCustom {
    private val follow = QFollowEntity.followEntity
    private val followingUser = QUserEntity.userEntity.`as`("followingUser")
    private val followerUser = QUserEntity.userEntity.`as`("followerUser")

    // 팔로잉 목록 조회 (N+1 문제 해결: fetch join)
    override fun findFollowingListWithUser(followerId: String, pageable: Pageable): Page<FollowEntity> {
        val content = queryFactory
            .selectFrom(follow)
            .innerJoin(follow.followingUser, followingUser).fetchJoin()
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }

    // 팔로워 목록 조회
    override fun findFollowerListWithUser(followingId: String, pageable: Pageable): Page<FollowEntity> {
        val content = queryFactory
            .selectFrom(follow)
            .innerJoin(follow.followerUser, followerUser).fetchJoin()
            .where(follow.followingId.eq(followingId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followingId.eq(followingId))
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }

    // 팔로잉 사용자 ID 목록만 조회 (성능 최적화)
    override fun findFollowingUserIds(followerId: String): List<String> {
        return queryFactory
            .select(follow.followingId)
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .fetch()
    }

    // 팔로워 사용자 ID 목록만 조회
    override fun findFollowerUserIds(followingId: String): List<String> {
        return queryFactory
            .select(follow.followerId)
            .from(follow)
            .where(follow.followingId.eq(followingId))
            .fetch()
    }
}
```

### 3. Service 레이어 구현 (N+1 문제 해결)

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val userRepository: UserRepository
) {
    // 방법 1: fetch join으로 한 번에 조회
    fun getFollowingList(userId: String, pageable: Pageable): Page<UserEntity> {
        return followRepository
            .findFollowingListWithUser(userId, pageable)
            .map { it.followingUser!! }
    }

    // 방법 2: ID 목록만 조회 후 배치 조회 (대용량 데이터)
    fun getFollowingListBatch(userId: String): List<UserEntity> {
        val followingUserIds = followRepository.findFollowingUserIds(userId)
        return if (followingUserIds.isEmpty()) {
            emptyList()
        } else {
            userRepository.findAllByIdIn(followingUserIds)
        }
    }

    // 팔로우 여부 확인 (인덱스 활용)
    fun isFollowing(followerId: String, followingId: String): Boolean {
        return followRepository.findByFollowerIdAndFollowingId(followerId, followingId) != null
    }

    // 팔로우 추가
    fun follow(followerId: String, followingId: String) {
        if (followerId == followingId) {
            throw IllegalArgumentException("자신을 팔로우할 수 없습니다")
        }
        val follow = FollowEntity(
            followerId = followerId,
            followingId = followingId
        )
        followRepository.save(follow)
    }

    // 언팔로우
    fun unfollow(followerId: String, followingId: String) {
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
    }
}
```

### 4. 인덱스 최적화 전략

**MySQL에 추가할 인덱스:**

```sql
-- 팔로우 조회 최적화
CREATE INDEX idx_follow_follower_created ON follow(follower_id, created_at DESC);
CREATE INDEX idx_follow_following_created ON follow(following_id, created_at DESC);

-- 팔로우 여부 확인 (유니크 제약)
CREATE UNIQUE INDEX idx_follow_unique ON follow(follower_id, following_id);
```

### 5. 성능 비교

| 방식 | 쿼리 수 | 데이터 로드 | 사용 시기 |
|------|--------|-----------|---------|
| N+1 쿼리 (최악) | 1 + N | 모두 로드 | 피해야 함 |
| fetch join | 1 | 필요한 것만 | 작은 목록 조회 |
| ID 배치 조회 | 2 | 필요한 것만 | 대용량 데이터 |

